129→export default async function createSimpleDeepAgent(
130→  model: BaseLanguageModel,
131→  conversationId: string,
132→  sandboxManager: ConversationSandboxManager,
133→): Promise<ReturnType<typeof createAgent>> {
134→  const session = await sandboxManager.getConversationSandbox(conversationId);
135→  const client = new MultiServerMCPClient({
136→    grafana: {
137→      transport: 'sse',
138→      url: configSchema.GRAFANA_MCP_URL!,
139→    },
140→  });
141→
142→  // 过滤，只剩下
143→  const FILTER_TOOLS = ['search_dashboards', 'list_datasources', 'get_dashboard_panel_queries', 'query_prometheus', 'list_prometheus_label_names', 'generate_deeplink', 'get_dashboard_by_uid'];
144→  const allMcpTools = (await client.getTools()).filter(tool => FILTER_TOOLS.includes(tool.name)) as DynamicStructuredTool[]
145→
146→  const middleware = [
147→    createToolErrorMiddleware(),
148→    vfsRelativePathMiddleware,
149→    createStrictToolEvictionMiddleware(session.backend),
150→  ]
151→
152→  return createDeepAgent({
153→    model: model,
154→    tools: allMcpTools,
155→    middleware,
156→    backend: session.backend,
157→    checkpointer: memory,
158→    skills: [SANDBOX_SKILLS_ROOT]
159→  });
160→}
